INSERT INTO questions (category_id, question_text, options, correct_index, difficulty) VALUES
('c0000000-0000-0000-0000-000000000002', 'Which Hollywood actor has starred in films including Interstellar and The Wolf of Wall Street?', '["Matthew McConaughey","Ryan Reynolds","Jim Carrey","Hugh Jackman"]', 0, 1),
('c0000000-0000-0000-0000-000000000002', 'Which of these quotes is from the film ''Planet of the Apes''?', '["\"Mrs. Robinson, you''re trying to seduce me. Aren''t you?\"","\"Take your stinking paws off me, you damned dirty ape.\"","\"Toga! Toga!\"","\"Attica! Attica!\""]', 1, 1),
('c0000000-0000-0000-0000-000000000002', 'What is the plot of the movie The Silence of the Lambs?', '["A tramp who has fallen in love with a blind flower girl saves money to help her medically.","Follows the rise and fall of a stock-broker living the high life.","A young F.B.I. cadet must receive the help of a cannibal to help catch another serial killer.","A former neo-nazi tries to prevent his brother from going down the same path that he did."]', 2, 1),
('c0000000-0000-0000-0000-000000000002', 'What is the plot of the movie Die Hard?', '["In a post-apocalyptic wasteland, a woman rebels against a tyrannical ruler.","The story of how the scandal of child molestation within the Boston Catholic church was uncovered.","A rat makes an unusual alliance with a young kitchen worker at a famous restaurant.","An NYPD officer tries to save his wife taken hostage by terrorists during a Christmas party."]', 3, 1),
('c0000000-0000-0000-0000-000000000002', 'Which of these quotes is from the film ''Dodgeball: A True Underdog Story''?', '["\"Nobody makes me bleed my own blood. Nobody!\"","\"Are you not entertained?\"","\"I have had it with these mother—— snakes on this mother—— plane!\"","\"What is this? A center for ants? How can we be expected to teach children to learn how to read…if they can''t even fit inside the building?\""]', 0, 1),
('c0000000-0000-0000-0000-000000000002', 'Which actor played the role of Iron Man in the Marvel Cinematic Universe?', '["Chris Evans","Robert Downey Jr.","Chris Hemsworth","Tom Holland"]', 1, 1),
('c0000000-0000-0000-0000-000000000002', 'Which of these quotes is from the film ''The Graduate''?', '["\"Soylent Green is people!\"","\"Round up the usual suspects.\"","\"Mrs. Robinson, you''re trying to seduce me. Aren''t you?\"","\"Just keep swimming.\""]', 2, 1),
('c0000000-0000-0000-0000-000000000002', 'What is the plot of the movie Forrest Gump?', '["A thief who steals secrets through dreams must plant an idea into the mind of a C.E.O.","The son of a city''s mastermind falls in love with a working-class prophet.","An insomniac and a soap maker form an underground organisation that evolves into much more.","Historical events unfold from the perspective of an Alabama man with an IQ of 75."]', 3, 1),
('c0000000-0000-0000-0000-000000000002', 'What is the plot of the movie The Terminator?', '["A human soldier is sent from 2029 to 1984 to stop an almost indestructible cyborg killing machine.","A Marine observes the effects of war on his fellow recruits from their boot camp training to fighting in a war.","The lives of mob hitmen, a boxer, a gangster and his wife, and a pair of bandits intertwine in four tales.","Historical events unfold from the perspective of an Alabama man with an IQ of 75."]', 0, 1),
('c0000000-0000-0000-0000-000000000002', 'In Star Wars, what color is Darth Vader''s lightsaber?', '["Blue","Red","Green","Purple"]', 1, 1),
